import os
import json
import time
import hashlib
from datetime import datetime, timedelta
from flask import Flask, request, jsonify

app = Flask(__name__)

class DiskCache:
    def __init__(self, cache_dir='cache', default_ttl=3600):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        os.makedirs(cache_dir, exist_ok=True)
    
    def _get_cache_key(self, url, params=None):
        key_string = f"{url}_{str(params)}"
        return hashlib.md5(key_string.encode()).hexdigest()
    
    def _is_expired(self, timestamp, ttl):
        return time.time() > timestamp + ttl
    
    def get(self, url, params=None):
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        if os.path.exists(cache_file):
            try:
                with open(cache_file, 'r') as f:
                    data = json.load(f)
                
                if not self._is_expired(data['timestamp'], data['ttl']):
                    return data['data']
                else:
                    os.remove(cache_file)
            except (json.JSONDecodeError, KeyError):
                if os.path.exists(cache_file):
                    os.remove(cache_file)
        
        return None
    
    def set(self, url, data, params=None, ttl=None):
        if ttl is None:
            ttl = self.default_ttl
        
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        cache_data = {
            'data': data,
            'timestamp': time.time(),
            'ttl': ttl
        }
        
        with open(cache_file, 'w') as f:
            json.dump(cache_data, f)
    
    def clear_expired(self):
        current_time = time.time()
        for filename in os.listdir(self.cache_dir):
            if filename.endswith('.json'):
                file_path = os.path.join(self.cache_dir, filename)
                try:
                    with open(file_path, 'r') as f:
                        data = json.load(f)
                    if self._is_expired(data['timestamp'], data['ttl']):
                        os.remove(file_path)
                except (json.JSONDecodeError, KeyError):
                    os.remove(file_path)

cache = DiskCache()

